import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { PokemonService } from '../../services/pokemon.service';
import { PokemonDetail } from '../../models/pokemon.model';
import { Location } from '@angular/common';

@Component({
  selector: 'app-pokemon-detail',
  templateUrl: './pokemon-detail.component.html',
  styleUrls: ['./pokemon-detail.component.scss']
})
export class PokemonDetailComponent implements OnInit {
  pokemon: PokemonDetail | null = null;
  isLoading = true;
  hasError = false;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private location: Location,
    private pokemonService: PokemonService
  ) {}

  ngOnInit(): void {
    this.route.paramMap.subscribe(params => {
      const name = params.get('name');
      if (name) {
        this.loadDetail(name);
      }
    });
  }

  private loadDetail(name: string): void {
    this.isLoading = true;
    this.hasError = false;

    this.pokemonService.getPokemonDetail(name).subscribe({
      next: (data: PokemonDetail) => {
        this.pokemon = data;
        this.isLoading = false;
      },
      error: () => {
        this.hasError = true;
        this.isLoading = false;
      }
    });
  }

  goBack(): void {
    this.location.back();
  }

  /** Restituisce il colore associato a un tipo */
  typeColor(typeName: string): string {
    const colors: Record<string, string> = {
      normal:   '#A8A878', fire:     '#F08030', water:    '#6890F0',
      electric: '#F8D030', grass:    '#78C850', ice:      '#98D8D8',
      fighting: '#C03028', poison:   '#A040A0', ground:   '#E0C068',
      flying:   '#A890F0', psychic:  '#F85888', bug:      '#A8B820',
      rock:     '#B8A038', ghost:    '#705898', dragon:   '#7038F8',
      dark:     '#705848', steel:    '#B8B8D0', fairy:    '#EE99AC',
    };
    return colors[typeName] ?? '#888';
  }

  capitalize(s: string): string {
    return s.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
  }

  /** Percentuale per la barra della stat (max teorico 255) */
  statPercent(value: number): number {
    return Math.min(100, Math.round((value / 255) * 100));
  }

  statColor(value: number): string {
    if (value >= 100) return '#22c55e';
    if (value >= 60)  return '#f7c948';
    return '#f87171';
  }

  getOfficialArtwork(): string {
    return this.pokemon?.sprites?.other?.['official-artwork']?.front_default
      ?? this.pokemon?.sprites?.front_default
      ?? '';
  }
}
<section class="detail-page">

  <!-- Loading -->
  <div *ngIf="isLoading" class="state-container">
    <div class="spinner"></div>
    <p>Caricamento dettagli…</p>
  </div>

  <!-- Error -->
  <div *ngIf="hasError" class="state-container error">
    <span>⚠️</span>
    <p>Impossibile caricare il Pokémon.</p>
    <button class="btn-back" (click)="goBack()">← Torna indietro</button>
  </div>

  <!-- Content -->
  <ng-container *ngIf="!isLoading && !hasError && pokemon">

    <!-- Back -->
    <button class="btn-back" (click)="goBack()">← Torna alla lista</button>

    <!-- Hero card -->
    <div class="hero-card">
      <div class="hero-left">
        <img
          [src]="getOfficialArtwork()"
          [alt]="pokemon.name"
          class="hero-sprite"
        />
      </div>

      <div class="hero-right">
        <p class="pokemon-number">#{{ pokemon.id.toString().padStart(3, '0') }}</p>
        <h1 class="pokemon-name">{{ capitalize(pokemon.name) }}</h1>

        <!-- Types -->
        <div class="types-row">
          <span
            *ngFor="let t of pokemon.types"
            class="type-pill"
            [style.background]="typeColor(t.type.name)"
          >
            {{ capitalize(t.type.name) }}
          </span>
        </div>

        <!-- Quick stats -->
        <div class="quick-stats">
          <div class="qs-item">
            <span class="qs-label">Altezza</span>
            <span class="qs-value">{{ (pokemon.height / 10).toFixed(1) }} m</span>
          </div>
          <div class="qs-item">
            <span class="qs-label">Peso</span>
            <span class="qs-value">{{ (pokemon.weight / 10).toFixed(1) }} kg</span>
          </div>
          <div class="qs-item">
            <span class="qs-label">Exp base</span>
            <span class="qs-value">{{ pokemon.base_experience ?? '—' }}</span>
          </div>
        </div>

        <!-- Abilities -->
        <div class="abilities">
          <p class="section-label">Abilità</p>
          <div class="ability-list">
            <span
              *ngFor="let a of pokemon.abilities"
              class="ability-pill"
              [class.hidden]="a.is_hidden"
            >
              {{ capitalize(a.ability.name) }}
              <span *ngIf="a.is_hidden" class="hidden-tag">nascosta</span>
            </span>
          </div>
        </div>
      </div>
    </div>

    <!-- Stats section -->
    <div class="stats-section">
      <h2 class="section-title">Statistiche Base</h2>
      <div class="stats-list">
        <div *ngFor="let s of pokemon.stats" class="stat-row">
          <span class="stat-name">{{ capitalize(s.stat.name) }}</span>
          <span class="stat-value">{{ s.base_stat }}</span>
          <div class="stat-bar-track">
            <div
              class="stat-bar-fill"
              [style.width.%]="statPercent(s.base_stat)"
              [style.background]="statColor(s.base_stat)"
            ></div>
          </div>
        </div>
      </div>
    </div>

    <!-- Moves preview -->
    <div class="moves-section">
      <h2 class="section-title">Mosse (prime 20)</h2>
      <div class="moves-grid">
        <span *ngFor="let m of pokemon.moves.slice(0, 20)" class="move-pill">
          {{ capitalize(m.move.name) }}
        </span>
      </div>
    </div>

  </ng-container>
</section>
